151→async function runSingleUpload(
152→	flags: UploadFlags,
153→	session: string,
154→): Promise<void> {
155→	const write = (msg: string) => {
156→		process.stdout.write(`${msg}\n`);
157→	};
158→	const writeError = (msg: string) => {
159→		process.stderr.write(`${msg}\n`);
160→	};
161→
162→	const credentials = loadCredentials();
163→	if (!credentials && !flags.dryRun) {
164→		writeError("Error: Not authenticated. Run `rudel login` first.");
165→		process.exitCode = 1;
166→		return;
167→	}
168→
169→	write(`Resolving session: ${session}`);
170→	let sessionInfo: Awaited<ReturnType<typeof resolveSession>>;
171→	try {
172→		sessionInfo = await resolveSession(session);
173→	} catch (error) {
174→		writeError(
175→			`Error: ${error instanceof Error ? error.message : String(error)}`,
176→		);
177→		process.exitCode = 1;
178→		return;
179→	}
180→	write(`Found session at: ${sessionInfo.transcriptPath}`);
181→
182→	write("Reading transcript...");
183→	let content: string;
184→	try {
185→		content = await readTranscript(sessionInfo.transcriptPath);
186→	} catch (error) {
187→		writeError(
188→			`Error reading transcript: ${error instanceof Error ? error.message : String(error)}`,
189→		);
190→		process.exitCode = 1;
191→		return;
192→	}
193→	write(`Transcript: ${content.length} bytes`);
194→
195→	const agentIds = extractAgentIds(content);
196→	let subagents: SubagentFile[] = [];
197→	if (agentIds.length > 0) {
198→		write(`Found ${agentIds.length} subagent(s): ${agentIds.join(", ")}`);
199→		subagents = await readSubagentFiles(
200→			sessionInfo.sessionDir,
201→			agentIds,
202→			sessionInfo.sessionId,
203→		);
204→		write(
205→			`Read ${subagents.length} subagent file(s): ${subagents.reduce((sum, s) => sum + s.content.length, 0)} bytes total`,
206→		);
207→	}
208→
209→	const gitInfo = await getGitInfo(sessionInfo.projectPath);
210→	if (gitInfo.repository) write(`Repository: ${gitInfo.repository}`);
211→	if (gitInfo.branch) write(`Branch: ${gitInfo.branch}`);
212→
213→	let tag = flags.tag;
214→	if (!tag && flags.classify) {
215→		write("Classifying session...");
216→		tag = (await classifySession(content)) ?? undefined;
217→		if (tag) write(`Classified as: ${tag}`);
218→	}
219→
220→	const organizationId =
221→		flags.org ?? (await getProjectOrgId(sessionInfo.projectPath));
222→	if (organizationId) write(`Organization: ${organizationId}`);
223→
224→	const request: IngestRequest = {
225→		sessionId: sessionInfo.sessionId,
226→		projectPath: sessionInfo.projectPath,
227→		repository: gitInfo.repository,
228→		gitRemote: gitInfo.gitRemote,
229→		packageName: gitInfo.packageName,
230→		gitBranch: gitInfo.branch,
231→		gitSha: gitInfo.sha,
232→		tag,
233→		content,
234→		subagents: subagents.length > 0 ? subagents : undefined,
235→		organizationId,
236→	};
237→
238→	if (flags.dryRun) {
239→		const preview = {
240→			...request,
241→			content: `[${request.content.length} bytes]`,
242→			subagents: request.subagents?.map((s) => ({
243→				...s,
244→				content: `[${s.content.length} bytes]`,
245→			})),
246→		};
247→		write("Dry run - would upload:");
248→		write(JSON.stringify(preview, null, 2));
249→		return;
250→	}
251→
252→	write("Uploading...");
253→	const result = await uploadSession(request, {
254→		endpoint: flags.endpoint,
255→		// biome-ignore lint/style/noNonNullAssertion: validated above with early return
256→		token: credentials!.token,
257→	});
258→
259→	if (result.success) {
260→		write("Upload successful!");
261→	} else {
262→		writeError(`Upload failed: ${result.error}`);
263→		process.exitCode = 1;
264→	}
265→}
266→
267→async function runUpload(
268→	flags: UploadFlags,
269→	...sessions: string[]
270→): Promise<void> {
271→	if (sessions.length === 0) {
272→		return runInteractiveUpload(flags);
273→	}
274→	return runSingleUpload(flags, sessions[0] as string);
275→}
