 15→async function runEnable(): Promise<void> {
 16→	p.intro("rudel enable");
 17→
 18→	// Verify auth (loads credentials + pings API)
 19→	const auth = await verifyAuth();
 20→	if (!auth.authenticated) {
 21→		p.log.error(auth.message);
 22→		p.outro("Run `rudel login` to authenticate.");
 23→		process.exitCode = 1;
 24→		return;
 25→	}
 26→
 27→	const { credentials } = auth;
 28→
 29→	// Fetch user's organizations
 30→	const client = createApiClient(credentials);
 31→	let orgs: { id: string; name: string; slug: string }[];
 32→	try {
 33→		orgs = await client.listMyOrganizations();
 34→	} catch {
 35→		p.log.error("Failed to fetch organizations. Check your connection.");
 36→		process.exitCode = 1;
 37→		return;
 38→	}
 39→
 40→	if (orgs.length === 0) {
 41→		p.log.error("No organizations found.");
 42→		p.outro("Create one at app.rudel.ai first.");
 43→		process.exitCode = 1;
 44→		return;
 45→	}
 46→
 47→	// Check if already configured for this project
 48→	const cwd = process.cwd();
 49→	const existingOrgId = await getProjectOrgId(cwd);
 50→	const existingOrg = existingOrgId
 51→		? orgs.find((o) => o.id === existingOrgId)
 52→		: undefined;
 53→
 54→	let selectedOrgId: string;
 55→
 56→	const [firstOrg] = orgs;
 57→	if (orgs.length === 1 && firstOrg) {
 58→		selectedOrgId = firstOrg.id;
 59→		p.log.info(`Using organization: ${firstOrg.name}`);
 60→	} else if (existingOrg) {
 61→		p.log.info(`Currently configured for: ${existingOrg.name}`);
 62→		selectedOrgId = existingOrg.id;
 63→	} else {
 64→		const selected = await p.select({
 65→			message: "Select an organization for this repository",
 66→			options: orgs.map((org) => ({
 67→				value: org.id,
 68→				label: org.name,
 69→				hint: org.slug,
 70→			})),
 71→		});
 72→
 73→		if (p.isCancel(selected)) {
 74→			p.cancel("Setup cancelled.");
 75→			return;
 76→		}
 77→
 78→		selectedOrgId = selected;
 79→		const selectedOrg = orgs.find((o) => o.id === selected);
 80→		if (selectedOrg) {
 81→			p.log.success(`Selected: ${selectedOrg.name}`);
 82→		}
 83→	}
 84→
 85→	await setProjectOrgId(cwd, selectedOrgId);
 86→
 87→	// Install hook via agent abstraction
 88→	const agent = getDefaultAgent();
 89→
 90→	if (agent.isHookInstalled()) {
 91→		p.log.info("Auto-upload hook is already enabled. Organization updated.");
 92→	} else {
 93→		agent.installHook();
 94→		p.log.success(`Auto-upload hook enabled in ${agent.getHookSettingsPath()}`);
 95→	}
 96→
 97→	// Check for existing sessions to upload (uses same scan logic as `upload`)
 98→	const sessions = await findSessionsForCwd(cwd);
 99→	if (sessions.length === 0) {
100→		p.outro("Done!");
101→		return;
102→	}
103→
104→	const shouldUpload = await p.confirm({
105→		message: `Found ${sessions.length} previous session(s). Upload them now?`,
106→		initialValue: false,
107→	});
108→
109→	if (p.isCancel(shouldUpload) || !shouldUpload) {
110→		p.outro("Done!");
111→		return;
112→	}
113→
114→	const endpoint = `${credentials.apiBaseUrl}/rpc`;
115→	let failed = 0;
116→
117→	await p.tasks(
118→		sessions.map((session, i) => ({
119→			title: `[${i + 1}/${sessions.length}] ${session.sessionId}`,
120→			task: async (message) => {
121→				message("Reading transcript...");
122→				try {
123→					const content = await readTranscript(session.transcriptPath);
124→					const agentIds = extractAgentIds(content);
125→					const sessionDir = dirname(session.transcriptPath);
126→					const subagents =
127→						agentIds.length > 0
128→							? await readSubagentFiles(sessionDir, agentIds, session.sessionId)
129→							: [];
130→
131→					message("Resolving git info...");
132→					const gitInfo = await getGitInfo(session.projectPath);
133→
134→					const request: IngestRequest = {
135→						sessionId: session.sessionId,
136→						projectPath: session.projectPath,
137→						repository: gitInfo.repository,
138→						gitBranch: gitInfo.branch,
139→						gitSha: gitInfo.sha,
140→						content,
141→						subagents: subagents.length > 0 ? subagents : undefined,
142→						organizationId: selectedOrgId,
143→					};
144→
145→					message("Uploading...");
146→					const result = await uploadSession(request, {
147→						endpoint,
148→						token: credentials.token,
149→					});
150→
151→					if (result.success) {
152→						return "Uploaded";
153→					}
154→					failed++;
155→					return `Failed: ${result.error}`;
156→				} catch (error) {
157→					failed++;
158→					return `Error: ${error instanceof Error ? error.message : String(error)}`;
159→				}
160→			},
161→		})),
162→	);
163→
164→	if (failed > 0) {
165→		p.log.error(`${failed} session(s) failed`);
166→	}
167→
168→	p.outro("Done!");
169→}
