 82→export async function batchUpload(
 83→	projects: ScannedProject[],
 84→	options: BatchOptions,
 85→	onProgress: (current: number, total: number, sessionId: string) => void,
 86→): Promise<BatchResult> {
 87→	const totalSessions = projects.reduce(
 88→		(sum, p) => sum + p.sessionIds.length,
 89→		0,
 90→	);
 91→	let completed = 0;
 92→	const result: BatchResult = { succeeded: 0, failed: 0, errors: [] };
 93→
 94→	for (const project of projects) {
 95→		for (const sessionId of project.sessionIds) {
 96→			completed++;
 97→			onProgress(completed, totalSessions, sessionId);
 98→
 99→			const outcome = await uploadOneSession(
100→				project.sessionDir,
101→				sessionId,
102→				project.decodedPath,
103→				options,
104→			);
105→
106→			if (outcome.success) {
107→				result.succeeded++;
108→			} else {
109→				result.failed++;
110→				result.errors.push({
111→					sessionId,
112→					project: project.displayPath,
113→					error: outcome.error ?? "Unknown error",
114→				});
115→			}
116→		}
117→	}
118→
119→	return result;
120→}
