 22→export interface GroupedProjects {
 23→	current?: ScannedProject;
 24→	subfolders: ScannedProject[];
 25→	others: ScannedProject[];
 26→}
 27→
 28→export async function scanProjects(): Promise<ScannedProject[]> {
 29→	let projectDirs: string[];
 30→	try {
 31→		projectDirs = await readdir(SESSIONS_BASE_DIR);
 32→	} catch {
 33→		return [];
 34→	}
 35→
 36→	const home = homedir();
 37→	const projects: ScannedProject[] = [];
 38→
 39→	for (const dir of projectDirs) {
 40→		const sessionDir = `${SESSIONS_BASE_DIR}/${dir}`;
 41→		let files: string[];
 42→		try {
 43→			files = await readdir(sessionDir);
 44→		} catch {
 45→			continue;
 46→		}
 47→
 48→		const sessionIds = files
 49→			.filter((f) => f.endsWith(".jsonl") && !f.startsWith("agent-"))
 50→			.map((f) => f.replace(/\.jsonl$/, ""));
 51→
 52→		if (sessionIds.length === 0) continue;
 53→
 54→		const decodedPath = await decodeProjectPath(dir);
 55→		const displayPath = decodedPath.startsWith(home)
 56→			? `~${decodedPath.slice(home.length)}`
 57→			: decodedPath;
 58→
 59→		projects.push({
 60→			encodedDir: dir,
 61→			decodedPath,
 62→			displayPath,
 63→			sessionDir,
 64→			sessionCount: sessionIds.length,
 65→			sessionIds,
 66→		});
 67→	}
 68→
 69→	return projects;
 70→}
 71→
 72→export function groupProjectsForCwd(
 73→	projects: ScannedProject[],
 74→	cwd: string,
 75→): GroupedProjects {
 76→	const current = projects.find((p) => p.decodedPath === cwd);
 77→	const subfolders = projects.filter(
 78→		(p) =>
 79→			p !== current &&
 80→			current !== undefined &&
 81→			p.decodedPath.startsWith(`${current.decodedPath}/`),
 82→	);
 83→	const others = projects.filter(
 84→		(p) => p !== current && !subfolders.includes(p),
 85→	);
 86→
 87→	subfolders.sort((a, b) => a.decodedPath.localeCompare(b.decodedPath));
 88→	others.sort((a, b) => a.displayPath.localeCompare(b.displayPath));
 89→
 90→	return { current, subfolders, others };
 91→}
