 93→export interface ProjectGroup {
 94→	displayName: string;
 95→	gitRemote: string | null;
 96→	projects: ScannedProject[];
 97→	totalSessions: number;
 98→	containsCwd: boolean;
 99→}
100→
101→function extractDisplayName(normalized: string): string {
102→	// "github.com/owner/repo" → "owner/repo"
103→	const parts = normalized.split("/");
104→	if (parts.length >= 3) {
105→		return parts.slice(1).join("/");
106→	}
107→	return normalized;
108→}
109→
110→export async function groupProjectsByRemote(
111→	projects: ScannedProject[],
112→	cwd: string,
113→): Promise<ProjectGroup[]> {
114→	const cache = await getRemoteCache();
115→	let cacheUpdated = false;
116→
117→	const remotes = await Promise.all(
118→		projects.map((p) => getGitRemoteUrl(p.decodedPath)),
119→	);
120→
121→	const grouped = new Map<
122→		string,
123→		{ remote: string; projects: ScannedProject[] }
124→	>();
125→	const ungrouped: ScannedProject[] = [];
126→
127→	for (let i = 0; i < projects.length; i++) {
128→		const project = projects[i] as ScannedProject;
129→		const remote = remotes[i];
130→
131→		if (remote) {
132→			const normalized = normalizeRemoteUrl(remote);
133→			// Cache newly resolved remotes
134→			if (getCachedRemote(cache, project.encodedDir) !== normalized) {
135→				cacheRemote(cache, project.encodedDir, normalized);
136→				cacheUpdated = true;
137→			}
138→			const existing = grouped.get(normalized);
139→			if (existing) {
140→				existing.projects.push(project);
141→			} else {
142→				grouped.set(normalized, { remote: normalized, projects: [project] });
143→			}
144→		} else {
145→			// Try cache for ungrouped projects
146→			const cached = getCachedRemote(cache, project.encodedDir);
147→			if (cached) {
148→				const existing = grouped.get(cached);
149→				if (existing) {
150→					existing.projects.push(project);
151→				} else {
152→					grouped.set(cached, { remote: cached, projects: [project] });
153→				}
154→			} else {
155→				ungrouped.push(project);
156→			}
157→		}
158→	}
159→
160→	const groups: ProjectGroup[] = [];
161→
162→	for (const [, entry] of grouped) {
163→		const containsCwd = entry.projects.some(
164→			(p) => cwd === p.decodedPath || cwd.startsWith(`${p.decodedPath}/`),
165→		);
166→		groups.push({
167→			displayName: extractDisplayName(entry.remote),
168→			gitRemote: entry.remote,
169→			projects: entry.projects,
170→			totalSessions: entry.projects.reduce((s, p) => s + p.sessionCount, 0),
171→			containsCwd,
172→		});
173→	}
174→
175→	// Second pass: match ungrouped projects to existing groups by path similarity.
176→	// Deleted Conductor workspaces have no git remote, but share a path prefix
177→	// (e.g. ~/conductor/workspaces/rudel/) with existing workspaces that do.
178→	const homeSegments = homedir().split("/").length;
179→	const remainingUngrouped: ScannedProject[] = [];
180→
181→	for (const project of ungrouped) {
182→		const match = findBestGroupByPath(project, groups, homeSegments);
183→		if (match) {
184→			match.projects.push(project);
185→			match.totalSessions += project.sessionCount;
186→			if (
187→				cwd === project.decodedPath ||
188→				cwd.startsWith(`${project.decodedPath}/`)
189→			) {
190→				match.containsCwd = true;
191→			}
192→		} else {
193→			remainingUngrouped.push(project);
194→		}
195→	}
196→
197→	for (const project of remainingUngrouped) {
198→		const containsCwd =
199→			cwd === project.decodedPath || cwd.startsWith(`${project.decodedPath}/`);
200→		groups.push({
201→			displayName: project.displayPath,
202→			gitRemote: null,
203→			projects: [project],
204→			totalSessions: project.sessionCount,
205→			containsCwd,
206→		});
207→	}
208→
209→	groups.sort((a, b) => {
210→		if (a.containsCwd !== b.containsCwd) return a.containsCwd ? -1 : 1;
211→		const aHasRemote = a.gitRemote !== null;
212→		const bHasRemote = b.gitRemote !== null;
213→		if (aHasRemote !== bHasRemote) return aHasRemote ? -1 : 1;
214→		return a.displayName.localeCompare(b.displayName);
215→	});
216→
217→	// Fire-and-forget cache write
218→	if (cacheUpdated) {
219→		cacheRemotes(cache);
220→	}
221→
222→	return groups;
223→}
224→
225→export function toSessionFiles(projects: ScannedProject[]): SessionFile[] {
226→	return projects.flatMap((project) =>
227→		project.sessionIds.map((sessionId) => ({
228→			sessionId,
229→			transcriptPath: `${project.sessionDir}/${sessionId}.jsonl`,
230→			projectPath: project.decodedPath,
231→		})),
232→	);
233→}
