235→/**
236→ * Find all sessions belonging to the same repository as `cwd`.
237→ * Uses the same scan + group-by-remote logic as the upload command.
238→ */
239→export async function findSessionsForCwd(cwd: string): Promise<SessionFile[]> {
240→	const projects = await scanProjects();
241→	if (projects.length === 0) return [];
242→
243→	const groups = await groupProjectsByRemote(projects, cwd);
244→	const cwdGroup = groups.find((g) => g.containsCwd);
245→	if (!cwdGroup) return [];
246→
247→	return toSessionFiles(cwdGroup.projects);
248→}
249→
250→function commonPrefixLength(a: string, b: string): number {
251→	const partsA = a.split("/");
252→	const partsB = b.split("/");
253→	let count = 0;
254→	for (let i = 0; i < Math.min(partsA.length, partsB.length); i++) {
255→		if (partsA[i] === partsB[i]) count++;
256→		else break;
257→	}
258→	return count;
259→}
260→
261→function findBestGroupByPath(
262→	project: ScannedProject,
263→	groups: ProjectGroup[],
264→	homeSegments: number,
265→): ProjectGroup | null {
266→	let bestGroup: ProjectGroup | null = null;
267→	let bestLen = 0;
268→	let secondBestLen = 0;
269→
270→	for (const group of groups) {
271→		if (!group.gitRemote) continue;
272→
273→		let groupBest = 0;
274→		for (const p of group.projects) {
275→			groupBest = Math.max(
276→				groupBest,
277→				commonPrefixLength(project.decodedPath, p.decodedPath),
278→			);
279→		}
280→
281→		if (groupBest > bestLen) {
282→			secondBestLen = bestLen;
283→			bestLen = groupBest;
284→			bestGroup = group;
285→		} else if (groupBest > secondBestLen) {
286→			secondBestLen = groupBest;
287→		}
288→	}
289→
290→	// Must extend beyond home dir AND be strictly better than second-best
291→	if (bestGroup && bestLen > homeSegments && bestLen > secondBestLen) {
292→		return bestGroup;
293→	}
294→	return null;
295→}
