  4→export interface GitInfo {
  5→	repository?: string;
  6→	gitRemote?: string;
  7→	packageName?: string;
  8→	branch?: string;
  9→	sha?: string;
 10→}
 11→
 12→/**
 13→ * Normalize a git remote URL to a canonical form: "github.com/owner/repo"
 14→ */
 15→export function normalizeRemoteUrl(url: string): string {
 16→	return url
 17→		.replace(/^(https?:\/\/|git@|ssh:\/\/)/, "")
 18→		.replace(/:/, "/")
 19→		.replace(/\.git$/, "");
 20→}
 21→
 22→/**
 23→ * Extract git metadata for a given project directory.
 24→ */
 25→export async function getGitInfo(cwd: string): Promise<GitInfo> {
 26→	const [remoteUrl, branch, sha, packageName] = await Promise.all([
 27→		getGitRemoteUrl(cwd),
 28→		getGitBranch(cwd),
 29→		getGitSha(cwd),
 30→		getPackageName(cwd),
 31→	]);
 32→
 33→	const gitRemote = remoteUrl ? normalizeRemoteUrl(remoteUrl) : undefined;
 34→	const repository = getRepositoryName(gitRemote, packageName, cwd);
 35→
 36→	return {
 37→		repository,
 38→		gitRemote,
 39→		packageName: packageName ?? undefined,
 40→		branch: branch ?? undefined,
 41→		sha: sha ?? undefined,
 42→	};
 43→}
 44→
 45→/**
 46→ * Extract a display name for the repository.
 47→ * Prefers owner/repo from git remote, falls back to package name, then dir name.
 48→ */
 49→function getRepositoryName(
 50→	gitRemote: string | undefined,
 51→	packageName: string | null,
 52→	cwd: string,
 53→): string | undefined {
 54→	if (gitRemote) {
 55→		// "github.com/owner/repo" → "owner/repo"
 56→		const parts = gitRemote.split("/");
 57→		if (parts.length >= 3) {
 58→			return parts.slice(1).join("/");
 59→		}
 60→		return gitRemote;
 61→	}
 62→	if (packageName) return packageName;
 63→	const dirName = cwd.split("/").pop();
 64→	return dirName ?? undefined;
 65→}
 66→
 67→async function getPackageName(cwd: string): Promise<string | null> {
 68→	try {
 69→		const gitRootResult =
 70→			await $`git -C ${cwd} rev-parse --show-toplevel`.quiet();
 71→		const gitRoot =
 72→			gitRootResult.exitCode === 0 ? gitRootResult.text().trim() : cwd;
 73→
 74→		const packageJsonPath = join(gitRoot, "package.json");
 75→		const packageFile = Bun.file(packageJsonPath);
 76→		if (await packageFile.exists()) {
 77→			try {
 78→				const packageJson = await packageFile.json();
 79→				if (packageJson.name) return packageJson.name;
 80→			} catch {
 81→				// Invalid JSON
 82→			}
 83→		}
 84→		return null;
 85→	} catch {
 86→		return null;
 87→	}
 88→}
 89→
 90→export async function getGitRemoteUrl(cwd: string): Promise<string | null> {
 91→	try {
 92→		const result = await $`git -C ${cwd} remote get-url origin`.quiet();
 93→		if (result.exitCode !== 0) return null;
 94→		return result.text().trim() || null;
 95→	} catch {
 96→		return null;
 97→	}
 98→}
 99→
100→async function getGitBranch(cwd: string): Promise<string | null> {
101→	try {
102→		const result = await $`git -C ${cwd} rev-parse --abbrev-ref HEAD`.quiet();
103→		if (result.exitCode !== 0) return null;
104→		return result.text().trim();
105→	} catch {
106→		return null;
107→	}
108→}
109→
110→async function getGitSha(cwd: string): Promise<string | null> {
111→	try {
112→		const result = await $`git -C ${cwd} rev-parse HEAD`.quiet();
113→		if (result.exitCode !== 0) return null;
114→		return result.text().trim();
115→	} catch {
116→		return null;
117→	}
118→}
