 7→
 8→type AuthSuccess = {
 9→	authenticated: true;
10→	credentials: Credentials;
11→	user: { id: string; email: string; name: string };
12→};
13→
14→type AuthFailure = {
15→	authenticated: false;
16→	reason: "no_credentials" | "token_expired" | "network_error";
17→	message: string;
18→};
