  8→import { readSubagentFiles } from "../lib/subagent-reader.js";
  9→import { extractAgentIds, readTranscript } from "../lib/transcript-reader.js";
 10→import { DEFAULT_ENDPOINT, type IngestRequest } from "../lib/types.js";
 11→import { uploadSession } from "../lib/uploader.js";
 12→import { disposeLogging, setupHookLogging } from "../logging.js";
 13→
 14→/**
 15→ * Hook-based session upload that reads session metadata from stdin.
 16→ * Designed to be called by the Claude Code plugin's SessionEnd hook.
 17→ * Runs silently — all output goes to the log file, not stdout.
 18→ */
 19→async function runHookUpload(): Promise<void> {
 20→	await setupHookLogging();
 21→	const logger = getLogger(["rudel", "cli", "hook"]);
 22→
 23→	try {
 24→		logger.debug("Hook upload started");
 25→
 26→		const config = await readConfig();
 27→
 28→		if (!config.apiKey) {
 29→			logger.debug("Not logged in, skipping session upload.");
 30→			return;
 31→		}
 32→
 33→		const stdinContent = await readStdin();
 34→		const input = parseStdinInput(stdinContent);
 35→
 36→		if (!input) {
 37→			logger.debug("No stdin input, exiting.");
 38→			return;
 39→		}
 40→
 41→		const { session_id, transcript_path, cwd } = input;
 42→		if (!session_id || !transcript_path) {
 43→			logger.error("Missing session_id or transcript_path");
 44→			return;
 45→		}
 46→
 47→		const content = await readTranscript(transcript_path);
 48→
 49→		const agentIds = extractAgentIds(content);
 50→		const sessionDir = dirname(transcript_path);
 51→		const subagents =
 52→			agentIds.length > 0
 53→				? await readSubagentFiles(sessionDir, agentIds, session_id)
 54→				: undefined;
 55→
 56→		const [gitInfo, tag] = await Promise.all([
 57→			getGitInfo(cwd),
 58→			classifySession(content),
 59→		]);
 60→
 61→		const request: IngestRequest = {
 62→			sessionId: session_id,
 63→			projectPath: cwd,
 64→			repository: gitInfo.repository,
 65→			gitBranch: gitInfo.branch,
 66→			gitSha: gitInfo.sha,
 67→			tag: tag ?? undefined,
 68→			content,
 69→			subagents: subagents?.length ? subagents : undefined,
 70→		};
 71→
 72→		const endpoint =
 73→			process.env.GAZED_INGEST_ENDPOINT ?? config.endpoint ?? DEFAULT_ENDPOINT;
 74→
 75→		logger.info(
 76→			"Uploading session {sessionId}, repo={repository}, branch={branch}, tag={tag}, bytes={bytes}, subagents={subagents}",
 77→			{
 78→				sessionId: request.sessionId,
 79→				repository: request.repository ?? "none",
 80→				branch: request.gitBranch ?? "none",
 81→				tag: request.tag ?? "none",
 82→				bytes: request.content.length,
 83→				subagents: request.subagents?.length ?? 0,
 84→			},
 85→		);
 86→
 87→		const result = await uploadSession(request, {
 88→			endpoint,
 89→			token: config.apiKey,
 90→		});
 91→
 92→		if (result.success) {
 93→			logger.info("Upload successful for session {sessionId}", {
 94→				sessionId: request.sessionId,
 95→			});
 96→		} else {
 97→			logger.error("Upload failed: {error}", { error: result.error });
 98→		}
 99→	} catch (error) {
100→		logger.error("Unexpected error: {error}", { error });
101→	} finally {
102→		await disposeLogging();
103→	}
104→}
105→
106→export const hookUploadCommand = buildCommand({
107→	loader: async () => ({ default: runHookUpload }),
108→	parameters: {},
109→	docs: {
110→		brief: "Upload session from Claude Code hook (reads stdin, logs to file)",
111→	},
112→});
