21→async function readStdin(): Promise<string> {
22→	const chunks: string[] = [];
23→	for await (const chunk of process.stdin) {
24→		chunks.push(typeof chunk === "string" ? chunk : chunk.toString());
25→	}
26→	return chunks.join("");
