19→	if (process.platform === "win32") {
20→		const chunks: Buffer[] = [];
21→		for await (const chunk of process.stdin) {
22→			chunks.push(Buffer.from(chunk));
23→		}
24→		return Buffer.concat(chunks).toString("utf8");
25→	}
26→
27→	const chunks: Uint8Array[] = [];
28→	try {
29→		for await (const chunk of Bun.stdin.stream()) {
30→			chunks.push(chunk);
31→		}
32→	} catch (error: unknown) {
33→		const code = (error as { code?: string }).code;
34→		if (code === "EBADF" || code === "ENXIO") {
35→			return "";
36→		}
37→		throw error;
38→	}
39→	return Buffer.concat(chunks).toString("utf8");
40→}
