42→export function parseStdinInput(input: string): HookStdinInput | null {
43→	if (!input.trim()) {
44→		return null;
45→	}
46→	try {
47→		return JSON.parse(input) as HookStdinInput;
48→	} catch {
49→		return null;
50→	}
51→}
