 3→import { getDefaultAgent } from "../lib/agents/index.js";
 4→
 5→async function runDisable(): Promise<void> {
 6→	const agent = getDefaultAgent();
 7→
 8→	if (!agent.isHookInstalled()) {
 9→		p.log.info("Auto-upload hook is not enabled.");
