						sessionId: session.sessionId,
						transcriptPath: session.transcriptPath,
						projectPath: session.projectPath,
						organizationId: selectedOrgId,
						error: errorMessage,
					});
					return `Error: ${errorMessage}`;
				}
			},
		})),
	);

	if (succeeded > 0) {
		p.log.success(`${succeeded} session(s) uploaded`);
	}
	if (failed > 0) {
		p.log.error(`${failed} session(s) failed`);
		for (const err of errors.slice(0, 5)) {
			p.log.warn(`  ${err.sessionId}: ${err.error}`);
		}
		if (errors.length > 5) {
			p.log.warn(`  ...and ${errors.length - 5} more`);
		}
	}

	p.outro("Done!");
}

export const enableCommand = buildCommand({
	loader: async () => ({ default: runEnable }),
	parameters: {},
	docs: {
		brief: "Enable automatic session upload via Claude Code hook",
	},
});

