  1→import { getLogger } from "@logtape/logtape";
  2→import { buildCommand } from "@stricli/core";
  3→import { loadCredentials } from "../../../lib/credentials.js";
  4→import { getGitInfo } from "../../../lib/git-info.js";
  5→import { getProjectOrgId } from "../../../lib/project-config.js";
  6→import { readSubagentFiles } from "../../../lib/subagent-reader.js";
  7→import {
  8→	extractAgentIds,
  9→	readTranscript,
 10→} from "../../../lib/transcript-reader.js";
 11→import type { IngestRequest } from "../../../lib/types.js";
 12→import { uploadSession } from "../../../lib/uploader.js";
 13→import { disposeLogging, setupHookLogging } from "../../../logging.js";
 14→
 15→interface HookInput {
 16→	session_id: string;
 17→	transcript_path: string;
 18→	cwd: string;
 19→}
 20→
 21→async function readStdin(): Promise<string> {
 22→	const chunks: string[] = [];
 23→	for await (const chunk of process.stdin) {
 24→		chunks.push(typeof chunk === "string" ? chunk : chunk.toString());
 25→	}
 26→	return chunks.join("");
 27→}
 28→
 29→async function runSessionEnd(): Promise<void> {
 30→	await setupHookLogging();
 31→	const logger = getLogger(["rudel", "cli", "hook"]);
 32→
 33→	try {
 34→		const raw = await readStdin();
 35→		if (!raw.trim()) return;
 36→
 37→		const input = JSON.parse(raw) as HookInput;
 38→		if (!input.session_id || !input.transcript_path) return;
 39→
 40→		const credentials = loadCredentials();
 41→		if (!credentials) return;
 42→
 43→		logger.info("Uploading session {sessionId}", {
 44→			sessionId: input.session_id,
 45→		});
 46→
 47→		const content = await readTranscript(input.transcript_path);
 48→
 49→		const agentIds = extractAgentIds(content);
 50→		const { dirname } = await import("node:path");
 51→		const sessionDir = dirname(input.transcript_path);
 52→		const subagents =
 53→			agentIds.length > 0
 54→				? await readSubagentFiles(sessionDir, agentIds, input.session_id)
 55→				: [];
 56→
 57→		const gitInfo = await getGitInfo(input.cwd);
 58→		const organizationId = await getProjectOrgId(input.cwd);
 59→
 60→		const request: IngestRequest = {
 61→			sessionId: input.session_id,
 62→			projectPath: input.cwd,
 63→			repository: gitInfo.repository,
 64→			gitRemote: gitInfo.gitRemote,
 65→			packageName: gitInfo.packageName,
 66→			gitBranch: gitInfo.branch,
 67→			gitSha: gitInfo.sha,
 68→			content,
 69→			subagents: subagents.length > 0 ? subagents : undefined,
 70→			organizationId,
 71→		};
 72→
 73→		const apiBase = process.env.RUDEL_API_BASE ?? credentials.apiBaseUrl;
 74→		const endpoint = `${apiBase}/rpc`;
 75→		const result = await uploadSession(request, {
 76→			endpoint,
 77→			token: credentials.token,
 78→			onRetry: (attempt, maxAttempts, error) => {
 79→				logger.warn(
 80→					"Retrying upload for {sessionId} ({attempt}/{maxAttempts}): {error}",
 81→					{ sessionId: input.session_id, attempt, maxAttempts, error },
 82→				);
 83→			},
 84→		});
 85→
 86→		if (result.success) {
 87→			logger.info(
 88→				"Upload successful for session {sessionId} (attempts: {attempts})",
 89→				{ sessionId: input.session_id, attempts: result.attempts },
 90→			);
 91→		} else {
