  1→import * as p from "@clack/prompts";
  2→import { buildCommand } from "@stricli/core";
  3→import { type BatchOptions, batchUpload } from "../lib/batch-uploader.js";
  4→import { classifySession } from "../lib/classifier.js";
  5→import { loadCredentials } from "../lib/credentials.js";
  6→import { getGitInfo } from "../lib/git-info.js";
  7→import { getProjectOrgId } from "../lib/project-config.js";
  8→import {
  9→	groupProjectsByRemote,
 10→	type ProjectGroup,
 11→	scanProjects,
 12→} from "../lib/project-scanner.js";
 13→import { resolveSession } from "../lib/session-resolver.js";
 14→import { readSubagentFiles } from "../lib/subagent-reader.js";
 15→import { extractAgentIds, readTranscript } from "../lib/transcript-reader.js";
 16→import {
 17→	DEFAULT_ENDPOINT,
 18→	type IngestRequest,
 19→	SESSION_TAGS,
 20→	type SessionTag,
 21→	type SubagentFile,
 22→} from "../lib/types.js";
 23→import { uploadSession } from "../lib/uploader.js";
 24→
 25→interface UploadFlags {
 26→	tag?: SessionTag;
 27→	endpoint: string;
 28→	classify: boolean;
 29→	dryRun: boolean;
 30→	org?: string;
 31→}
 32→
 33→async function runInteractiveUpload(flags: UploadFlags): Promise<void> {
 34→	const credentials = loadCredentials();
 35→	if (!credentials && !flags.dryRun) {
 36→		p.log.error("Not authenticated. Run `rudel login` first.");
 37→		process.exitCode = 1;
 38→		return;
 39→	}
 40→
 41→	p.intro("rudel upload");
 42→
 43→	const spin = p.spinner();
 44→	spin.start("Scanning projects...");
 45→	const projects = await scanProjects();
 46→	spin.stop(`Found ${projects.length} project(s)`);
 47→
 48→	if (projects.length === 0) {
 49→		p.log.warn("No projects with sessions found in ~/.claude/projects/");
 50→		p.outro("Nothing to upload.");
 51→		return;
 52→	}
 53→
 54→	const cwd = process.cwd();
 55→	spin.start("Grouping by git remote...");
 56→	const groups = await groupProjectsByRemote(projects, cwd);
 57→	spin.stop(`Found ${groups.length} group(s)`);
 58→
 59→	const options: Array<{
 60→		value: ProjectGroup;
 61→		label: string;
 62→		hint: string;
 63→	}> = [];
 64→	const preSelected: ProjectGroup[] = [];
 65→
 66→	for (const group of groups) {
 67→		const label =
 68→			group.projects.length > 1
 69→				? group.displayName
 70→				: (group.projects[0]?.displayPath ?? group.displayName);
 71→		const hint =
 72→			group.projects.length > 1
 73→				? `${sessionCountHint(group.totalSessions)}, ${group.projects.length} locations`
 74→				: sessionCountHint(group.totalSessions);
 75→		options.push({ value: group, label, hint });
 76→		if (group.containsCwd) {
 77→			preSelected.push(group);
 78→		}
 79→	}
 80→
 81→	const selected = await p.multiselect({
 82→		message: "Select projects to upload",
 83→		options,
 84→		initialValues: preSelected,
 85→		required: true,
 86→	});
 87→
 88→	if (p.isCancel(selected)) {
 89→		p.cancel("Upload cancelled.");
 90→		return;
 91→	}
 92→
 93→	const selectedProjects = selected.flatMap((g) => g.projects);
 94→	const totalSessions = selected.reduce((sum, g) => sum + g.totalSessions, 0);
 95→	p.log.info(
 96→		`Uploading ${totalSessions} session(s) from ${selectedProjects.length} project(s)`,
 97→	);
 98→
 99→	const batchOpts: BatchOptions = {
100→		tag: flags.tag,
101→		classify: flags.classify,
102→		dryRun: flags.dryRun,
103→		org: flags.org,
104→		uploadConfig: {
105→			endpoint: flags.endpoint,
106→			token: credentials?.token ?? "",
107→		},
108→	};
109→
110→	const uploadSpin = p.spinner();
111→	uploadSpin.start("Uploading sessions...");
112→
113→	const result = await batchUpload(
114→		selectedProjects,
115→		batchOpts,
116→		(current, total, _sessionId, status) => {
117→			uploadSpin.message(
118→				status
119→					? `[${current}/${total}] ${status}`
120→					: `[${current}/${total}] Uploading...`,
121→			);
122→		},
123→	);
124→
125→	uploadSpin.stop("Upload complete");
126→
127→	if (result.succeeded > 0) {
128→		p.log.success(`${result.succeeded} session(s) uploaded successfully`);
129→	}
130→	if (result.failed > 0) {
131→		p.log.error(`${result.failed} session(s) failed`);
132→		for (const err of result.errors.slice(0, 5)) {
133→			p.log.warn(`  ${err.project}/${err.sessionId}: ${err.error}`);
134→		}
135→		if (result.errors.length > 5) {
136→			p.log.warn(`  ...and ${result.errors.length - 5} more`);
137→		}
138→	}
139→
140→	if (flags.dryRun) {
141→		p.outro("Dry run complete — no sessions were uploaded.");
142→	} else {
143→		p.outro("Done!");
144→	}
145→
146→	if (result.failed > 0) {
147→		process.exitCode = 1;
148→	}
149→}
150→
151→function sessionCountHint(count: number): string {
152→	return `${count} session${count !== 1 ? "s" : ""}`;
153→}
154→
155→async function runSingleUpload(
156→	flags: UploadFlags,
157→	session: string,
158→): Promise<void> {
159→	const write = (msg: string) => {
160→		process.stdout.write(`${msg}\n`);
161→	};
162→	const writeError = (msg: string) => {
163→		process.stderr.write(`${msg}\n`);
164→	};
165→
166→	const credentials = loadCredentials();
167→	if (!credentials && !flags.dryRun) {
168→		writeError("Error: Not authenticated. Run `rudel login` first.");
169→		process.exitCode = 1;
170→		return;
171→	}
172→
173→	write(`Resolving session: ${session}`);
174→	let sessionInfo: Awaited<ReturnType<typeof resolveSession>>;
175→	try {
176→		sessionInfo = await resolveSession(session);
177→	} catch (error) {
178→		writeError(
179→			`Error: ${error instanceof Error ? error.message : String(error)}`,
180→		);
181→		process.exitCode = 1;
182→		return;
183→	}
184→	write(`Found session at: ${sessionInfo.transcriptPath}`);
185→
186→	write("Reading transcript...");
187→	let content: string;
188→	try {
189→		content = await readTranscript(sessionInfo.transcriptPath);
190→	} catch (error) {
191→		writeError(
192→			`Error reading transcript: ${error instanceof Error ? error.message : String(error)}`,
193→		);
194→		process.exitCode = 1;
195→		return;
196→	}
197→	write(`Transcript: ${content.length} bytes`);
198→
199→	const agentIds = extractAgentIds(content);
200→	let subagents: SubagentFile[] = [];
201→	if (agentIds.length > 0) {
202→		write(`Found ${agentIds.length} subagent(s): ${agentIds.join(", ")}`);
203→		subagents = await readSubagentFiles(
204→			sessionInfo.sessionDir,
205→			agentIds,
206→			sessionInfo.sessionId,
207→		);
208→		write(
209→			`Read ${subagents.length} subagent file(s): ${subagents.reduce((sum, s) => sum + s.content.length, 0)} bytes total`,
210→		);
211→	}
212→
213→	const gitInfo = await getGitInfo(sessionInfo.projectPath);
214→	if (gitInfo.repository) write(`Repository: ${gitInfo.repository}`);
215→	if (gitInfo.branch) write(`Branch: ${gitInfo.branch}`);
216→
217→	let tag = flags.tag;
218→	if (!tag && flags.classify) {
219→		write("Classifying session...");
220→		tag = (await classifySession(content)) ?? undefined;
221→		if (tag) write(`Classified as: ${tag}`);
222→	}
223→
