  1→import * as p from "@clack/prompts";
  2→import {
  3→	claudeCodeAdapter,
  4→	getAdapter,
  5→	getAvailableAdapters,
  6→	groupProjectsForCwd,
  7→	type ScannedProject,
  8→	type SessionFile,
  9→} from "@rudel/agent-adapters";
 10→import { buildCommand } from "@stricli/core";
 11→import { classifySession } from "../lib/classifier.js";
 12→import { loadCredentials } from "../lib/credentials.js";
 13→import { getGitInfo } from "../lib/git-info.js";
 14→import { getProjectOrgId } from "../lib/project-config.js";
 15→import { resolveSession } from "../lib/session-resolver.js";
 16→import {
 17→	DEFAULT_ENDPOINT,
 18→	SESSION_TAGS,
 19→	type SessionTag,
 20→} from "../lib/types.js";
 21→import { type UploadConfig, uploadSession } from "../lib/uploader.js";
 22→
 23→interface UploadFlags {
 24→	tag?: SessionTag;
 25→	endpoint: string;
 26→	classify: boolean;
 27→	dryRun: boolean;
 28→	org?: string;
 29→}
 30→
 31→async function runInteractiveUpload(flags: UploadFlags): Promise<void> {
 32→	const credentials = loadCredentials();
 33→	if (!credentials && !flags.dryRun) {
 34→		p.log.error("Not authenticated. Run `rudel login` first.");
 35→		process.exitCode = 1;
 36→		return;
 37→	}
 38→
 39→	p.intro("rudel upload");
 40→
 41→	const spin = p.spinner();
 42→	spin.start("Scanning projects...");
 43→
 44→	const adapters = getAvailableAdapters();
 45→	const allProjects: ScannedProject[] = [];
 46→	for (const adapter of adapters) {
 47→		const projects = await adapter.scanAllSessions();
 48→		allProjects.push(...projects);
 49→	}
 50→
 51→	spin.stop(`Found ${allProjects.length} project(s)`);
 52→
 53→	if (allProjects.length === 0) {
 54→		p.log.warn("No projects with sessions found.");
 55→		p.outro("Nothing to upload.");
 56→		return;
 57→	}
 58→
 59→	const cwd = process.cwd();
 60→	const grouped = groupProjectsForCwd(allProjects, cwd);
 61→
 62→	const options: Array<{
 63→		value: ScannedProject;
 64→		label: string;
 65→		hint: string;
 66→	}> = [];
 67→	const preSelected: ScannedProject[] = [];
 68→
 69→	for (const proj of grouped.current) {
 70→		options.push({
 71→			value: proj,
 72→			label: `[${getAdapterName(proj.source)}] ${proj.displayPath}`,
 73→			hint: sessionCountHint(proj.sessionCount),
 74→		});
 75→		preSelected.push(proj);
 76→	}
 77→
 78→	for (const sub of grouped.subfolders) {
 79→		const relative = sub.projectPath.slice(cwd.length + 1);
 80→		options.push({
 81→			value: sub,
 82→			label: `  [${getAdapterName(sub.source)}] ${relative}`,
 83→			hint: sessionCountHint(sub.sessionCount),
 84→		});
 85→		preSelected.push(sub);
 86→	}
 87→
 88→	for (const other of grouped.others) {
 89→		options.push({
 90→			value: other,
 91→			label: `[${getAdapterName(other.source)}] ${other.displayPath}`,
 92→			hint: sessionCountHint(other.sessionCount),
 93→		});
 94→	}
 95→
 96→	const selected = await p.multiselect({
 97→		message: "Select projects to upload",
 98→		options,
 99→		initialValues: preSelected,
100→		required: true,
101→	});
102→
103→	if (p.isCancel(selected)) {
104→		p.cancel("Upload cancelled.");
105→		return;
106→	}
107→
108→	const totalSessions = selected.reduce(
109→		(sum, proj) => sum + proj.sessionCount,
110→		0,
111→	);
112→	p.log.info(
113→		`Uploading ${totalSessions} session(s) from ${selected.length} project(s)`,
114→	);
115→
116→	const uploadConfig: UploadConfig = {
117→		endpoint: flags.endpoint,
118→		token: credentials?.token ?? "",
119→	};
120→
121→	const uploadSpin = p.spinner();
122→	uploadSpin.start("Uploading sessions...");
123→
124→	let succeeded = 0;
125→	let failed = 0;
126→	let completed = 0;
127→	const errors: Array<{ sessionId: string; project: string; error: string }> =
128→		[];
129→
130→	for (const project of selected) {
131→		const adapter = getAdapter(project.source);
132→		const gitInfo = await getGitInfo(project.projectPath);
133→		const organizationId =
134→			flags.org ?? (await getProjectOrgId(project.projectPath));
135→
136→		for (const session of project.sessions) {
137→			completed++;
138→			uploadSpin.message(`[${completed}/${totalSessions}] Uploading...`);
139→
140→			try {
141→				const request = await adapter.buildUploadRequest(session, {
142→					tag: flags.tag,
143→					gitInfo,
144→					organizationId,
145→				});
146→
147→				if (!flags.tag && flags.classify) {
148→					const classified = await classifySession(request.content);
149→					if (classified) {
150→						(request as { tag?: string }).tag = classified;
151→					}
152→				}
153→
154→				if (flags.dryRun) {
155→					succeeded++;
156→					continue;
157→				}
158→
159→				const result = await uploadSession(request, uploadConfig);
160→				if (result.success) {
161→					succeeded++;
162→				} else {
163→					failed++;
164→					errors.push({
165→						sessionId: session.sessionId,
166→						project: project.displayPath,
167→						error: result.error ?? "Unknown error",
168→					});
169→				}
170→			} catch (error) {
171→				failed++;
172→				errors.push({
173→					sessionId: session.sessionId,
174→					project: project.displayPath,
175→					error: error instanceof Error ? error.message : String(error),
176→				});
177→			}
178→		}
179→	}
180→
181→	uploadSpin.stop("Upload complete");
182→
183→	if (succeeded > 0) {
184→		p.log.success(`${succeeded} session(s) uploaded successfully`);
185→	}
186→	if (failed > 0) {
187→		p.log.error(`${failed} session(s) failed`);
188→		for (const err of errors.slice(0, 5)) {
189→			p.log.warn(`  ${err.project}/${err.sessionId}: ${err.error}`);
190→		}
191→		if (errors.length > 5) {
192→			p.log.warn(`  ...and ${errors.length - 5} more`);
193→		}
194→	}
195→
196→	if (flags.dryRun) {
197→		p.outro("Dry run complete — no sessions were uploaded.");
198→	} else {
199→		p.outro("Done!");
200→	}
201→
202→	if (failed > 0) {
203→		process.exitCode = 1;
204→	}
205→}
206→
207→function getAdapterName(source: string): string {
208→	try {
209→		return getAdapter(source).name;
210→	} catch {
211→		return source;
212→	}
213→}
214→
215→function sessionCountHint(count: number): string {
216→	return `${count} session${count !== 1 ? "s" : ""}`;
217→}
218→
219→async function runSingleUpload(
220→	flags: UploadFlags,
221→	session: string,
222→): Promise<void> {
223→	const write = (msg: string) => {
224→		process.stdout.write(`${msg}\n`);
225→	};
226→	const writeError = (msg: string) => {
227→		process.stderr.write(`${msg}\n`);
228→	};
229→
230→	const credentials = loadCredentials();
231→	if (!credentials && !flags.dryRun) {
232→		writeError("Error: Not authenticated. Run `rudel login` first.");
233→		process.exitCode = 1;
234→		return;
235→	}
236→
237→	write(`Resolving session: ${session}`);
238→	let sessionInfo: Awaited<ReturnType<typeof resolveSession>>;
239→	try {
240→		sessionInfo = await resolveSession(session);
241→	} catch (error) {
242→		writeError(
243→			`Error: ${error instanceof Error ? error.message : String(error)}`,
244→		);
245→		process.exitCode = 1;
246→		return;
247→	}
248→	write(`Found session at: ${sessionInfo.transcriptPath}`);
249→
250→	const gitInfo = await getGitInfo(sessionInfo.projectPath);
251→	if (gitInfo.repository) write(`Repository: ${gitInfo.repository}`);
